function LoadForm()
{
  SetEdad();

  //Cierra el grupo de dependencias
  if(Ctrl('main').GetMode()=="SHOW")
    Ctrl("vgChildsCV_1").SetXValue("1");

  if(Ctrl('main').GetMode()!="LIST")
  {
    Ctrl('c_nro_cuil_hid').SetXValue(Ctrl('c_nro_cuil').GetXValue());
    Ctrl('c_sexo_hid').SetXValue(Ctrl('c_sexo').GetXValue());
  }
  if (Ctrl('main').GetMode()=="NEW")
  {
    if (Ctrl('oi_tipo_documento'))
      Ctrl('oi_tipo_documento').SetXValue("1");

      //Setea el origen como INT  si es modo NEW, ya que el alta por NS gener aun CV INT
      Ctrl('c_origen').SetXValue('INT');
  }

  if (Ctrl('main').GetMode()=="NEW")
    Ctrl("oi_afjp").SetXValue('1');

  if (Ctrl('main').GetMode()=="SHOW")
  {
    //Disponible
    if (Ctrl('c_estado').GetXValue() == "D")
    {
      CtrlEnabled('NOLLAMAR',true);
      CtrlEnabled('EFECTIVIZADO',true);
      CtrlEnabled('LEGALES',true);
      CtrlEnabled('DISPONIBLE',false);
    }

    //EFECTIVIZADO
    if (Ctrl('c_estado').GetXValue() == "E")
    {
      CtrlEnabled('NOLLAMAR',false);
      CtrlEnabled('EFECTIVIZADO',false);
      CtrlEnabled('LEGALES',true);
      CtrlEnabled('DISPONIBLE',true);
    }

    //NOLLAMAR
    if (Ctrl('c_estado').GetXValue() == "N")
    {
      CtrlEnabled('NOLLAMAR',false);
      CtrlEnabled('EFECTIVIZADO',false);
      CtrlEnabled('LEGALES',true);
      CtrlEnabled('DISPONIBLE',true);
    }

    //Reasignable
    if (Ctrl('c_estado').GetXValue() == "R")
    {
      CtrlEnabled('NOLLAMAR',false);
      CtrlEnabled('EFECTIVIZADO',false);
      CtrlEnabled('LEGALES',true);
      CtrlEnabled('DISPONIBLE',false);
    }

     //Vencido
    if (Ctrl('c_estado').GetXValue() == "V")
    {
      CtrlEnabled('NOLLAMAR',false);
      CtrlEnabled('EFECTIVIZADO',false);
      CtrlEnabled('LEGALES',true);
      CtrlEnabled('DISPONIBLE',false);
    }

    //En Dotacion
    if (Ctrl('c_estado').GetXValue() == "A")
    {
      CtrlEnabled('NOLLAMAR',false);
      CtrlEnabled('EFECTIVIZADO',false);
      CtrlEnabled('LEGALES',false);
      CtrlEnabled('DISPONIBLE',false);
    }

     //Acuerdo Seclo
    if (Ctrl('c_estado').GetXValue() == "S")
    {
      CtrlEnabled('NOLLAMAR',false);
      CtrlEnabled('EFECTIVIZADO',false);
      CtrlEnabled('LEGALES',false);
      CtrlEnabled('DISPONIBLE',false);
    }

    //Conflictivo Pendientes
    if (Ctrl('c_estado').GetXValue() == "P")
    {
      CtrlEnabled('NOLLAMAR',false);
      CtrlEnabled('EFECTIVIZADO',false);
      CtrlEnabled('LEGALES',false);
      CtrlEnabled('DISPONIBLE',false);
    }

    //Estado Judicial
    if (Ctrl('c_estado').GetXValue() == "J")
    {
      CtrlEnabled('NOLLAMAR',false);
      CtrlEnabled('EFECTIVIZADO',false);
      CtrlEnabled('LEGALES',false);
      CtrlEnabled('DISPONIBLE',false);
    }

  }
}

function SetCuil()
{
	Ctrl('c_nro_cuil_hid').SetXValue(Ctrl('c_nro_cuil').GetXValue());
	if (Ctrl('c_nro_cuil').GetXValue()!='')
	{
		var cuilRes;  
	  var nSQL = GetProxy().SQLService();
	  cuilRes = nSQL.GetOBJ(Ctrl("main").getResource("QRY_VAL_CUIL"), "<PARAM c_nro_cuil=\""+Ctrl('c_nro_cuil_hid').GetCValue()+"\" c_nro_doc=\""+Ctrl('c_nro_doc').GetCValue()+"\" />");
	  if(cuilRes.flag == "1")
	  {
	    alert('El CUIL ingresado ya se encuentra registrado');
	    Ctrl('c_nro_cuil').SetXValue('');	    
	    return false;
	  }
	}


  var cuil;
  cuil = Ctrl('c_nro_cuil').GetXValue();
  cuil = cuil.replace('-', "");
  if(cuil.length == 11) {
    var ppio, medio, fin;
    ppio = cuil.substr(0,2);
    medio = cuil.substr(2,8);
    fin = cuil.substr(10,1);  
    cuil = ppio + '-' + medio + '-' + fin;
    Ctrl('c_nro_cuil').SetXValue(cuil);
  }
  else
    Ctrl('c_nro_cuil').SetError("El largo del cuil es incorrecto.");
}

