function Trim(strin)
{
	var strout="", strprev=" ", strnew="", t, c;

	for (t=0; t<strin.length; t++)
	{
		c=strin.charCodeAt(t);
		strnew=(c<32 && c>0)?" ":strin.charAt(t);
		if ((strprev!=strnew) || (strnew!=" "))
		{
			strout+=strnew;
			strprev=strnew;
		}
	}
	if ((strout.length!=0) && (strnew==" ")) strout=strout.substr(0,strout.length-1);

	return strout;
}

