function Save()
{ 
  if (Ctrl('main').GetMode()=="NEW")
  {  
	    if(ValidaCelular())
	    {
		    	//valido que el número de documento sea numérico y positivo sin importar el tipo de documento
		  	if ( isNaN(Ctrl('c_nro_doc_hid').GetXValue()) || Ctrl('c_nro_doc_hid').GetXValue().substring(0,1)=='-' ) 
			  {
					alert("El Documento debe ser numérico");
					return false;
			  }  

		    //Si el tipo de documento es DNI saca los puntos y controla que sean solo numeros
		    var dni = Ctrl('c_nro_doc_hid').GetXValue();
		    dni = Replace(dni, '.', "");                

		    Ctrl('c_nro_doc_hid').SetXValue(dni);
		    if (Ctrl('oi_tipo_documento').GetXValue() == 1) 
		    {
		      if (Ctrl('c_nro_doc_hid').GetXValue().length != 7 && Ctrl('c_nro_doc_hid').GetXValue().length != 8) 
		      {
		        alert("El largo del Documento es incorrecto");
		        return false;
		      }
		      if (parseInt(dni, 10).toString() != Ctrl('c_nro_doc_hid').GetXValue()) 
		      {
		        alert("El Documento debe ser numérico");
		        return false;
		      }
		    }
		    if (val_doc())
		    {
		      if(Ctrl('c_nro_cuil_hid').GetXValue() != "")
		      {
		        var oiNac = Ctrl('oi_nacionalidad').GetXValue();				
						if(oiNac==1)
						{//Valido que el DNI sea el mismo que se carga en el CUIL, si la nacionalidad es argentina  
						    var cuil = Ctrl('c_nro_cuil_hid').GetXValue().replace('-', "");
							  var doc = cuil.substr((10-dni.length),dni.length);

						    if(doc != dni) 
						    {
						    	alert("El documento no coincide con el ingresado en el CUIL.");
						    	return false;
						    }
		        }

		        if(val_cuil())
		        {
		          Ctrl('f_actualizacion_hid').SetXValue(datetime2str(NowDate()));
		          Ctrl('f_alta_cv_hid').SetXValue(date2str(NowDate()));
		          //var nro_doc;
		          //nro_doc = Ctrl('c_nro_doc').GetCValue();
		          //Ctrl('c_cv_hid').SetCValue('INT' + nro_doc);
		          Ctrl('c_cv_hid').SetCValue('INT' + dni);
		          if(validaciones())          	
		          	Ctrl('main').DoEvent('SAVE');          
		        }                                                        
		      }
		      else
		      {
		        Ctrl('f_actualizacion_hid').SetXValue(datetime2str(NowDate()));
		        Ctrl('f_alta_cv_hid').SetXValue(date2str(NowDate()));

		        //var nro_doc;
		        //nro_doc = Ctrl('c_nro_doc').GetCValue();
		        //Ctrl('c_cv_hid').SetCValue('INT' + nro_doc);
		        Ctrl('c_cv_hid').SetCValue('INT' + dni);
		        if(validaciones())          	
		        	Ctrl('main').DoEvent('SAVE');
		      }
		    }
  		}
  	}

  if (Ctrl('main').GetMode()=="EDIT")
  {  
		if(ValidaCelular())
		{
 			if(Ctrl('c_nro_cuil_hid').GetXValue() != "")
  		{
	      //Si el tipo de documento es DNI saca los puntos y controla que sean solo numeros
		    var dni = Ctrl('c_nro_doc_hid').GetXValue();
		    dni = Replace(dni, '.', "");       

	    	//Valido que el DNI sea el mismo que se carga en el CUIL , si la nacionalidad es Argentina   
	    	var oiNac = Ctrl('oi_nacionalidad').GetXValue();				
				if(oiNac==1)
				{
		    	var cuil = Ctrl('c_nro_cuil_hid').GetXValue().replace('-', "");
			  	var doc = cuil.substr((10-dni.length),dni.length);

		    	if(doc != dni) 
		    	{
		    	alert("El documento no coincide con el ingresado en el CUIL.");
		    	return false;
		    	}
    		}

      	if(val_cuil())
      	{
        	Ctrl('f_actualizacion_hid').SetXValue(datetime2str(NowDate()));
        	if(validaciones())          	
        	Ctrl('main').DoEvent('SAVE');
      	}
    	}
  		else
  		{  
  			if(validaciones())          	
    		Ctrl('main').DoEvent('SAVE');
  		}
  	}
  }	
	else
	{
	return false;
	}

}
































function val_f_nacim (myThis)
{
  if (myThis.GetXValue() != "")
  {
    if (myThis.GetXValue() >= date2str(NowDate()))
    {
      myThis.SetError('La fecha de Nacimiento debe ser anterior a Hoy');
      return false;
    }
    else return true;
    var anio = str2number(myThis.GetXValue().substr(0,4));
    anio = anio + 18;
    var fecha = number2str(anio);
    fecha += myThis.GetXValue().substr(4,2);
    fecha += myThis.GetXValue().substr(6,2);
    if (date2str(NowDate()) <= fecha)
    {
      myThis.SetError('La persona debe ser mayor de edad');
      return false;
    }
    else return true;
  }
  else return true;
}

function val_f_est_civil(myThis)
{
  if (myThis.GetXValue() != "")
  {
    if (myThis.GetXValue()  >= date2str(NowDate()))
    {
      myThis.SetError('La fecha de Estado Civil debe ser anterior a Hoy');
      return false;
    }
    if (myThis.GetXValue() <= Ctrl('f_nacim').GetXValue())
    {
      myThis.SetError('La fecha de Estado Civil debe ser posterior a la fecha de Nacimiento');
      return false;
    }
    if(Ctrl("oi_estado_civil").GetXValue()=='1' || Ctrl("oi_estado_civil").GetXValue()=='6')
    {
      myThis.SetError('El estado civil es incorrecto');
      return false;
    }
    else return true;
  }
  else return true;
}

function val_f_ingreso_pais (myThis)
{
  if (myThis.GetXValue() != "")
  {
    if (myThis.GetXValue() <= Ctrl('f_nacim').GetXValue() || myThis.GetXValue() >=  date2str(NowDate()))
    {
      myThis.SetError('La fecha de Ingreso al pais debe ser posterior a la fecha de Nacimiento y anterior a Hoy');
      return false;
    }
    else return true;
  }
  else return true;
}

