function val_fechaEC()
{
  var ec;  
  var nSQL = GetProxy().SQLService();

  ec = nSQL.GetOBJ(Ctrl("main").getResource("QRY_EST_CIVIL"), "<PARAM oi_estado_civil=\""+Ctrl('oi_estado_civil').GetXValue()+"\" />");

  if(ec.flag == "1" && Ctrl("f_est_civil").GetXValue()=="")
