function ValidaCelular(){
	if (Ctrl('c_pais_cel').GetXValue()!="" && Ctrl('c_area_cel').GetXValue()!="" && Ctrl('te_celular').GetXValue()!="" )
	{ 
		var cod_pais = Ctrl('c_pais_cel').GetCValue();
		var celular = Ctrl('te_celular').GetCValue();
		var cod_area = Ctrl('c_area_cel').GetCValue();
		//Valido como condicion principal que el codigo de país sea 54
		if (cod_pais==54){
			var valido_cod_area = cod_area.substr(0,1);

			//Valido que el primer número de la cadena código de área sea 1, 2  o 3
			if(valido_cod_area=="1" || valido_cod_area=="2" || valido_cod_area=="3" )
			{
				cod_area = cod_area.length;
				var celu = celular.length;
				suma_celular = cod_area + celu;

				var valido_celular = celular.substr(0,2);
				//Valido que la suma entre el código de area y el celular debe dar un total de 10 numeros
				if(suma_celular==10){

					if(valido_celular=="15"){
						alert('El número de Celular no debe comenzar con 15.');
						return false;
					}
					else
					{
						return true;
					}
				}
				else
				{ 
					if(valido_celular=="15")
					{
						alert('El número de Celular no debe comenzar con 15');
						return false;
					}
					else
					{
						alert('La cantidad de dígitos entre el número de Celular y código de área debe ser 10.');
						return false;
					}
				}
			}	
			else
			{
				alert('El número de Área Celular debe comenzar con 1, 2 o 3.');
				return false;
			}

		}
		else{
			//retorna true y no valida porque el codigo país no es 54
			return true;
		}

	}
	else
	{
		//retorna true. El celular debe estar completo como condicion para validar
		return true;
	}
}
